SELECT busi_id FROM ecm_busi_metadata
app_attr_id IN ( SELECT app_attr_id FROM ecm_app_attr WHERE app_code IN
#{appCode}
AND attr_code = #{item.attrCode} )
AND DATE(app_attr_val) BETWEEN SUBSTRING_INDEX(#{item.appAttrValue}, ',', 1) AND SUBSTRING_INDEX(#{item.appAttrValue}, ',', -1)
AND app_attr_val LIKE CONCAT(#{item.appAttrValue}, '%')
AND app_attr_val = #{item.appAttrValue}
GROUP BY busi_id HAVING COUNT(1) = #{size}

SELECT busi_id FROM ecm_busi_metadata

    
        app_attr_id in (SELECT app_attr_id FROM ecm_app_attr where app_code in
        
            #{appCode}
        
        and attr_code = #{item.attrCode})
        
            
                
                    and app_attr_val between SUBSTR(#{item.appAttrValue}, 1, INSTR(#{item.appAttrValue}, ',') - 1)
                    and SUBSTR(#{item.appAttrValue}, INSTR(#{item.appAttrValue}, ',') +1)
                
                
                    and app_attr_val = #{item.appAttrValue}
                
            
        
        
            and app_attr_val like CONCAT(#{item.appAttrValue}, '%')
        
        
            and app_attr_val = #{item.appAttrValue}
        
    

group by busi_id
having count(1) = #{size}
